def process_transactions(transactions, accounts):
    """
    Process financial transactions and update account balances.
    
    Args:
        transactions: List of transaction dictionaries with keys 'account_id', 'amount', 'type'
        accounts: Dictionary mapping account_id to current balance
    
    Returns:
        Updated accounts dictionary
    """
    for transaction in transactions:
        account_id = transaction['account_id']
        amount = transaction['amount']
        transaction_type = transaction['type']
        
        if account_id in accounts:
            if transaction_type == 'deposit':
                accounts[account_id] += amount
            elif transaction_type == 'withdrawal':
                accounts[account_id] -= amount
            elif transaction_type == 'transfer':
                # Assuming transfer has 'to_account_id' in transaction
                to_account_id = transaction.get('to_account_id')
                if to_account_id and to_account_id in accounts:
                    accounts[account_id] -= amount
                    accounts[to_account_id] += amount
    
    return accounts

def update_account_balances(transactions, accounts):
    """
    Alternative implementation with more robust error handling.
    
    Args:
        transactions: List of transaction dictionaries
        accounts: Dictionary of account balances
    
    Returns:
        Updated accounts dictionary
    """
    for transaction in transactions:
        try:
            account_id = transaction['account_id']
            amount = float(transaction['amount'])
            
            if account_id not in accounts:
                accounts[account_id] = 0
            
            if transaction['type'] == 'deposit':
                accounts[account_id] += amount
            elif transaction['type'] == 'withdrawal':
                accounts[account_id] -= amount
            elif transaction['type'] == 'transfer':
                to_account_id = transaction.get('to_account_id')
                if to_account_id and to_account_id in accounts:
                    accounts[account_id] -= amount
                    accounts[to_account_id] += amount
        except (KeyError, ValueError, TypeError):
            continue
    
    return accounts